import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse('{"title":"message-bus-pattern","description":"","frontmatter":{"title":"message-bus-pattern","concept":"消息总线模式","concept_id":"message-bus-pattern","aliases":[],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md"],"related_concepts":["[[multi-agent-orchestrator]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/message-bus-pattern.md","filePath":"wiki/concepts/message-bus-pattern.md","lastUpdated":null}'),n={name:"wiki/concepts/message-bus-pattern.md"};function o(i,e,c,l,h,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="消息总线模式-message-bus-pattern" tabindex="-1">消息总线模式 (Message Bus Pattern) <a class="header-anchor" href="#消息总线模式-message-bus-pattern" aria-label="Permalink to &quot;消息总线模式 (Message Bus Pattern)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>一种极端去中心化的多 Agent 工作流。基于事件驱动架构（Pub/Sub），所有 Agent 发布它们完成的事件至中央总线，其它具有相应工具/处理能力的 Agent 自发响应订阅并接手下游工作。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>动态寻址</strong>：由于没有强主干控制（如 Orchestrator 模式），非常利于处理完全不可预测的工作链。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md</a>）</li><li><strong>高韧性</strong>：单一职能的 Agent 崩溃不会影响全系统，只需再起一个订阅相同事件的克隆即可恢复工作。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>不建议用于强时序任务（如写代码编译）。适合在类似“安全应急响应分发”、“互联网舆情监控警报体系”中部署。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/multi-agent-orchestrator.html">multi-agent-orchestrator</a> — 可参考 Orchestrator，与此模式形成了中心化与去中心化的两端。</li></ul>',9)])])}const m=t(n,[["render",o]]);export{d as __pageData,m as default};
